#include <bits/stdc++.h>
using namespace std;

const int N=3e5+10;

int n,a[N],f[N][61],ans;

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    memset(f,-1,sizeof(f));
    for(int i=1;i<=n;i++){
        f[i][a[i]]=i-1;
        ans=max(ans,a[i]);
        for(int j=a[i]+1;;j++){
            f[i][j]=f[f[i][j-1]][j-1];
            if(f[i][j]==-1)
                break;
            ans=max(ans,j);
        }
    }
    printf("%d",ans);
    return 0;
}
